import axios from 'axios';

const API = axios.create({
  baseURL: 'http://localhost:8080/api',
  headers: { 'Content-Type': 'application/json' },
});

// ── AUTH ─────────────────────────────────────────────
export const registerUser  = (data) => API.post('/users/register', data);
export const loginUser     = (data) => API.post('/users/login', data);
export const getUserById   = (id)   => API.get(`/users/${id}`);
export const updateUser    = (id, data) => API.put(`/users/${id}`, data);
export const getAllUsers    = ()    => API.get('/users');
export const getUsersByRole = (role) => API.get(`/users/role/${role}`);
export const deleteUser    = (id)   => API.delete(`/users/${id}`);

// ── EVENTS ───────────────────────────────────────────
export const getAllEvents    = (sortBy) => API.get('/events', { params: sortBy ? { sortBy } : {} });
export const filterEvents   = (params) => API.get('/events/filter', { params });
export const getEventById   = (id)     => API.get(`/events/${id}`);
export const getEventsByType = (type)  => API.get(`/events/type/${type}`);
export const searchEvents   = (name)   => API.get('/events/search', { params: { name } });
export const getEventsByOrganiser = (id) => API.get(`/events/organiser/${id}`);
export const createEvent    = (data)   => API.post('/events', data);
export const updateEvent    = (id, data) => API.put(`/events/${id}`, data);
export const deleteEvent    = (id)     => API.delete(`/events/${id}`);

// ── LOCATIONS ────────────────────────────────────────
export const getAllLocations   = ()     => API.get('/locations');
export const getLocationById   = (id)   => API.get(`/locations/${id}`);
export const createLocation    = (data) => API.post('/locations', data);
export const updateLocation    = (id, data) => API.put(`/locations/${id}`, data);
export const deleteLocation    = (id)   => API.delete(`/locations/${id}`);
export const searchLocations   = (name) => API.get('/locations/search', { params: { name } });

// ── SHOW SLOTS ───────────────────────────────────────
export const getAllSlots       = ()     => API.get('/slots');
export const getSlotById       = (id)   => API.get(`/slots/${id}`);
export const getSlotsByEvent   = (id)   => API.get(`/slots/event/${id}`);
export const getSlotsByDate    = (date) => API.get(`/slots/date/${date}`);
export const getAvailableSlots = ()     => API.get('/slots/available');
export const getAvailableSeats = (slotId) => API.get(`/slots/${slotId}/seats/available`);
export const createSlot        = (data) => API.post('/slots', data);
export const updateSlot        = (id, data) => API.put(`/slots/${id}`, data);
export const deleteSlot        = (id)   => API.delete(`/slots/${id}`);

// ── SEATS ────────────────────────────────────────────
export const getSeatsByLocation = (locId) => API.get(`/seats/location/${locId}`);
export const createSeat         = (locId, data) => API.post(`/seats/location/${locId}`, data);
export const updateSeat         = (id, data) => API.put(`/seats/${id}`, data);
export const deleteSeat         = (id)   => API.delete(`/seats/${id}`);

// ── RESERVATIONS ─────────────────────────────────────
export const bookSeats          = (data) => API.post('/reservations/book', data);
export const getReservationsByUser = (id) => API.get(`/reservations/user/${id}`);
export const getReservationById  = (id)  => API.get(`/reservations/${id}`);
export const getReservationsByOrganiser = (id) => API.get(`/reservations/organiser/${id}`);
export const getAllReservations  = ()    => API.get('/reservations');

// ── TRANSACTIONS ─────────────────────────────────────
export const processPayment     = (data) => API.post('/transactions/pay', data);
export const getTransactionsByUser = (id) => API.get(`/transactions/user/${id}`);
export const getTransactionsByOrganiser = (id) => API.get(`/transactions/organiser/${id}`);
export const getAllTransactions  = ()    => API.get('/transactions');
export const getTransactionByReservation = (resId) => API.get(`/transactions/reservation/${resId}`);

// ── CANCELLATIONS ────────────────────────────────────
export const cancelReservation  = (data) => API.post('/cancellations', data);
export const getCancellationsByUser = (id) => API.get(`/cancellations/user/${id}`);
export const getAllCancellations = ()    => API.get('/cancellations');
export const updateRefundStatus = (id, status) => API.put(`/cancellations/${id}/refund-status`, null, { params: { status } });

// ── NOTIFICATIONS ────────────────────────────────────
export const getNotificationsByUser = (id) => API.get(`/notifications/user/${id}`);
export const getAllNotifications = ()  => API.get('/notifications');
export const deleteNotification = (id) => API.delete(`/notifications/${id}`);

export default API;
